import { withDb } from "./db.mjs";

export async function run(now = new Date().toISOString()) {
  const nowDate = new Date(now);

  await withDb(async (db) => {
    // Read raw facts from the embedded account document
    const account = await db.collection("accounts").findOne({});
    const { account_id } = account;

    const regulatoryFlags = account.regulatoryFlags || [];
    const invoices = account.invoices || [];
    const shipments = account.shipments || [];
    const supportCases = account.supportCases || [];
    const usage = account.usage || {};

    // Check qualification: tier must be strategic or enterprise
    const qualifyingTiers = ["strategic", "enterprise"];
    if (!qualifyingTiers.includes(String(account.tier || "").toLowerCase())) {
      await persistNonQualifying(db, account);
      return;
    }

    // Derive risk signals (in display order per RULES.md)
    const activeSignals = [];

    // 1. Regulatory hold: open regulatory flag
    const hasRegulatoryHold = regulatoryFlags.some(f => f.status === "open");
    if (hasRegulatoryHold) activeSignals.push("Regulatory hold");

    // 2. Overdue invoice: unpaid/overdue, past due date, amountCents >= 2,500,000 ($25,000)
    const hasOverdueInvoice = invoices.some(inv => {
      if (inv.status === "paid") return false;
      if (inv.amountCents < 2_500_000) return false;
      const dueDate = new Date(inv.dueDate);
      return dueDate < nowDate;
    });
    if (hasOverdueInvoice) activeSignals.push("Overdue invoice");

    // 3. Delayed shipment: no deliveredDate AND past slaDate
    const hasDelayedShipment = shipments.some(s => {
      if (s.deliveredDate) return false;
      const slaDate = new Date(s.slaDate);
      return slaDate < nowDate;
    });
    if (hasDelayedShipment) activeSignals.push("Delayed shipment");

    // 4. Escalated support: open case with high or critical severity
    const hasEscalatedSupport = supportCases.some(c =>
      c.status === "open" && (c.severity === "high" || c.severity === "critical")
    );
    if (hasEscalatedSupport) activeSignals.push("Escalated support");

    // 5. Usage decline: current <= prior * 0.7
    if (
      typeof usage.priorPeriodUnits === "number" &&
      typeof usage.currentPeriodUnits === "number" &&
      usage.priorPeriodUnits > 0 &&
      usage.currentPeriodUnits <= usage.priorPeriodUnits * 0.7
    ) {
      activeSignals.push("Usage decline");
    }

    // Check if qualifies (at least one signal)
    if (activeSignals.length === 0) {
      await persistNonQualifying(db, account);
      return;
    }

    // Determine status
    const status = "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";

    // Build risk_summary
    const riskSummary = `${activeSignals.length} signals: ${activeSignals.join(", ")}`;

    // Owner routing (deduped, fixed order)
    const ownerSet = new Set();
    const ownerOrder = ["Legal", "Finance", "Customer Success", "Support"];
    if (activeSignals.includes("Regulatory hold")) ownerSet.add("Legal");
    if (activeSignals.includes("Overdue invoice")) ownerSet.add("Finance");
    if (activeSignals.includes("Delayed shipment")) ownerSet.add("Customer Success");
    if (activeSignals.includes("Usage decline")) ownerSet.add("Customer Success");
    if (activeSignals.includes("Escalated support")) ownerSet.add("Support");
    const owners = ownerOrder.filter(o => ownerSet.has(o));

    // top owner is first in the deduped owner list
    const topOwner = owners[0];
    const nextStep = `${topOwner} recovery review by 16:00`;

    // Customer-facing message (no internal IDs/codes, >50 chars)
    const signalDescriptions = {
      "Regulatory hold": "an open regulatory compliance matter requiring immediate attention",
      "Overdue invoice": "an outstanding invoice that has passed its due date",
      "Delayed shipment": "a shipment that has exceeded its expected delivery window",
      "Escalated support": "an open support case with elevated severity requiring urgent resolution",
      "Usage decline": "a significant decline in product usage that may indicate adoption challenges",
    };
    const signalText = activeSignals.map(s => signalDescriptions[s]).join("; ");
    const customerMessage = `Your account has been flagged for proactive attention due to the following: ${signalText}. Our team is actively working to address these matters and will be in touch shortly.`;

    // Clear existing persisted data
    await db.collection("workflow_state").deleteMany({});
    await db.collection("owner_tasks").deleteMany({});
    await db.collection("customer_messages").deleteMany({});
    await db.collection("audit_events").deleteMany({});

    // Persist workflow_state
    await db.collection("workflow_state").insertOne({
      account_id,
      account_name: account.name,
      status,
      risk_summary: riskSummary,
      next_step: nextStep,
      created_at: nowDate,
    });

    // Persist owner_tasks (one per owner group)
    const dueAt = new Date(nowDate);
    dueAt.setDate(dueAt.getDate() + 3);
    for (const owner of owners) {
      await db.collection("owner_tasks").insertOne({
        account_id,
        owner_group: owner,
        title: `${owner} recovery review`,
        due_at: dueAt,
        status: "open",
      });
    }

    // Persist customer_messages (one message)
    await db.collection("customer_messages").insertOne({
      account_id,
      body: customerMessage,
      created_at: nowDate,
    });

    // Persist audit_events (one customer-visible event)
    await db.collection("audit_events").insertOne({
      account_id,
      event_type: "escalation_initiated",
      description: `At-risk escalation initiated for account ${account.name}. ${riskSummary}. Assigned to: ${owners.join(", ")}.`,
      customer_visible: true,
      created_at: nowDate,
    });
  });
}

async function persistNonQualifying(db, account) {
  await db.collection("workflow_state").deleteMany({});
  await db.collection("owner_tasks").deleteMany({});
  await db.collection("customer_messages").deleteMany({});
  await db.collection("audit_events").deleteMany({});

  await db.collection("workflow_state").insertOne({
    account_id: account.account_id,
    account_name: account.name,
    status: "Monitoring — no escalation required.",
    next_step: "Continue standard monitoring.",
    risk_summary: "0 signals",
    created_at: new Date(),
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

