import { withDb } from "./db.mjs";

export async function run(now = new Date().toISOString()) {
  const nowDate = new Date(now);

  await withDb(async (db) => {
    const account = await db.collection("accounts").findOne({});
    const { invoices, shipments, regulatoryFlags, supportCases, usage } = account;

    const qualifyingTiers = ["strategic", "enterprise"];
    if (!qualifyingTiers.includes(account.tier)) {
      await persist(db, {
        account,
        escalate: false,
        status: "Monitoring — no escalation required.",
        next_step: "Continue standard monitoring.",
        risk_summary: "0 signals: ",
        owners: [],
      });
      return;
    }

    const signals = [];

    if (regulatoryFlags.some(f => f.status === "open"))
      signals.push("Regulatory hold");

    if (invoices.some(inv => inv.status === "overdue" && inv.amountCents >= 2_500_000))
      signals.push("Overdue invoice");

    if (shipments.some(s => !s.deliveredDate && new Date(s.slaDate) < nowDate))
      signals.push("Delayed shipment");

    if (supportCases.some(c => c.status === "open" && ["high", "critical"].includes(c.severity)))
      signals.push("Escalated support");

    if (usage && usage.currentPeriodUnits <= usage.priorPeriodUnits * 0.7)
      signals.push("Usage decline");

    if (signals.length === 0) {
      await persist(db, {
        account,
        escalate: false,
        status: "Monitoring — no escalation required.",
        next_step: "Continue standard monitoring.",
        risk_summary: "0 signals: ",
        owners: [],
      });
      return;
    }

    const ownerMap = {
      "Regulatory hold": "Legal",
      "Overdue invoice": "Finance",
      "Delayed shipment": "Customer Success",
      "Usage decline": "Customer Success",
      "Escalated support": "Support",
    };
    const ownerOrder = ["Legal", "Finance", "Customer Success", "Support"];
    const ownerSet = new Set(signals.map(s => ownerMap[s]));
    const owners = ownerOrder.filter(o => ownerSet.has(o));
    const topOwner = owners[0];

    await persist(db, {
      account,
      escalate: true,
      status: "At-risk escalation active with executive recovery owner routing and customer-visible audit history.",
      next_step: `${topOwner} recovery review by 16:00`,
      risk_summary: `${signals.length} signals: ${signals.join(", ")}`,
      owners,
      nowDate,
    });
  });
}

async function persist(db, { account, escalate, status, next_step, risk_summary, owners, nowDate }) {
  await db.collection("workflow_state").deleteMany({});
  await db.collection("owner_tasks").deleteMany({});
  await db.collection("customer_messages").deleteMany({});
  await db.collection("audit_events").deleteMany({});

  await db.collection("workflow_state").insertOne({
    account_id: account._id,
    account_name: account.name,
    status,
    next_step,
    risk_summary,
  });

  if (!escalate) return;

  const dueAt = new Date(nowDate);
  dueAt.setDate(dueAt.getDate() + 3);

  for (const owner of owners) {
    await db.collection("owner_tasks").insertOne({
      owner,
      title: `${owner} recovery review`,
      due_at: dueAt,
      status: "open",
    });
  }

  await db.collection("customer_messages").insertOne({
    account_name: account.name,
    message: `Your account has been flagged for proactive review. Our team has identified areas that require attention and has assigned the appropriate specialists to work with you. We are committed to ensuring your continued success and will be reaching out shortly to discuss next steps and our recovery plan.`,
  });

  await db.collection("audit_events").insertOne({
    event_type: "escalation_initiated",
    description: `At-risk escalation initiated. ${risk_summary}. Assigned owners: ${owners.join(", ")}.`,
    customer_visible: true,
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

